import strawberry
from strawberry import Schema, Query, Field
from strawberry_graphql import GraphQLSchema
from sqlalchemy import create_engine
from sqlalchemy.orm import sessionmaker

# Define the database connection and engine
engine = create_engine("postgresql://user:password@localhost/database")
Session = sessionmaker(bind=engine)

# Define the GraphQL schema
class Product:
    id: int
    name: str
    description: str
    price: float
    reviews: List[Review]
    sellers: List[Seller]
    categories: List[Category]
    images: List[Image]

class Review:
    id: int
    product_id: int
    rating: int
    comment: str

class Seller:
    id: int
    name: str
    email: str

class Category:
    id: int
    name: str

class Image:
    id: int
    url: str

# Define the GraphQL query
@strawberry.type
class Query:
    products: List[Product] = strawberry.field(resolver=lambda: Session.query(Product).all())
    product_by_id: Product = strawberry.field(resolver=lambda id: Session.query(Product).get(id))

# Define the GraphQL schema
schema = GraphQLSchema(query=Query)

# Create a GraphQL API using Strawberry
api = strawberry.GraphQLAPI(schema)